import time
import random
random.seed(42)
from txn_simulator import Workload
from workloads import WORKLOAD_1, WORKLOAD_3

# Test WORKLOAD_1 insertion speed
workload = Workload(WORKLOAD_1)
n = workload.num_txns

all_keys = set()
for i in range(n):
    for op in workload.txns[i]:
        all_keys.add(op[1])
key_list = sorted(all_keys, key=lambda x: int(x))
key_to_idx = {k: i for i, k in enumerate(key_list)}
K = len(key_to_idx)
print(f'WORKLOAD_1: K={K}, n={n}')

txn_ops = []
txn_lens = []
for i in range(n):
    ops = []
    for op in workload.txns[i]:
        is_w = 1 if op[0] == 'w' else 0
        ki = key_to_idx[op[1]]
        pos = int(op[2])
        tl = int(op[3])
        ops.append((is_w, ki, pos, tl))
    txn_ops.append(tuple(ops))
    txn_lens.append(ops[0][3] if ops else 0)

def fast_eval(seq):
    write_end = [0] * K
    any_end = [-1] * K
    total_cost = 0
    for idx in seq:
        txn = txn_ops[idx]
        tl = txn_lens[idx]
        ts = 1
        for (is_w, ki, pos, _) in txn:
            ae = any_end[ki]
            if ae >= 0:
                if is_w:
                    ks = ae + 1
                else:
                    we = write_end[ki]
                    ks = we + 1 if we > 0 else 0
                c = ks - pos + 1
                if c > ts:
                    ts = c
        te = ts + tl - 1
        cost = te - total_cost
        if cost > 0:
            total_cost += cost
        for (is_w, ki, pos, _) in txn:
            kt = ts + pos - 1
            if is_w:
                if kt > write_end[ki]:
                    write_end[ki] = kt
            if kt > any_end[ki]:
                any_end[ki] = kt
    return total_cost

def find_best_insert_old(seq, txn_idx):
    best_cost = float('inf')
    best_pos = 0
    m = len(seq)
    for pos in range(m + 1):
        candidate = seq[:pos] + [txn_idx] + seq[pos:]
        cost = fast_eval(candidate)
        if cost < best_cost:
            best_cost = cost
            best_pos = pos
    return best_pos, best_cost

