import time, random
random.seed(42)
from txn_simulator import Workload
from workloads import WORKLOAD_1

workload = Workload(WORKLOAD_1)
n = workload.num_txns

# Array-based setup
all_keys = set()
for i in range(n):
    for op in workload.txns[i]:
        all_keys.add(op[1])
key_list = sorted(all_keys, key=lambda x: int(x))
key_to_idx = {k: i for i, k in enumerate(key_list)}
K = len(key_to_idx)

txn_ops_arr = []
txn_lens_arr = []
for i in range(n):
    ops = []
    for op in workload.txns[i]:
        is_w = 1 if op[0] == 'w' else 0
        ki = key_to_idx[op[1]]
        pos = int(op[2])
        tl = int(op[3])
        ops.append((is_w, ki, pos, tl))
    txn_ops_arr.append(tuple(ops))
    txn_lens_arr.append(ops[0][3] if ops else 0)

# Dict-based (original)
txn_data_dict = []
for i in range(n):
    ops = []
    for op in workload.txns[i]:
        ops.append((op[0], op[1], int(op[2]), int(op[3])))
    txn_data_dict.append(ops)

def fast_eval_dict(seq):
    key_state = {}
    total_cost = 0
    for i in range(len(seq)):
        txn = txn_data_dict[seq[i]]
        txn_len = txn[0][3]
        txn_start = 1
        for (op_type, key, pos, _) in txn:
            if key in key_state:
                state = key_state[key]
                if op_type == 'w':
                    key_start = state[1] + 1
                else:
                    key_start = state[0] + 1 if state[0] > 0 else 0
                constraint = key_start - pos + 1
                if constraint > txn_start:
                    txn_start = constraint
        txn_end = txn_start + txn_len - 1
        cost = txn_end - total_cost
        if cost < 0:
            cost = 0
        total_cost += cost
        for (op_type, key, pos, _) in txn:
            key_time = txn_start + pos - 1
            if key in key_state:
                state = key_state[key]
                if op_type == 'w':
                    if key_time > state[0]:
                        state[0] = key_time
                if key_time > state[1]:
                    state[1] = key_time
            else:
                if op_type == 'w':
                    key_state[key] = [key_time, key_time]
                else:
                    key_state[key] = [0, key_time]
    return total_cost

def fast_eval_arr(seq):
    write_end = [0] * K
    any_end = [-1] * K
    total_cost = 0
    for idx in seq:
        txn = txn_ops_arr[idx]
        tl = txn_lens_arr[idx]
        ts = 1
        for (is_w, ki, pos, _) in txn:
            ae = any_end[ki]
            if ae >= 0:
                if is_w:
                    ks = ae + 1
                else:
                    we = write_end[ki]
                    ks = we + 1 if we > 0 else 0
                c = ks - pos + 1
                if c > ts:
                    ts = c
        te = ts + tl - 1
        cost = te - total_cost
        if cost > 0:
            total_cost += cost
        for (is_w, ki, pos, _) in txn:
            kt = ts + pos - 1
            if is_w:
                if kt > write_end[ki]:
                    write_end[ki] = kt
            if kt > any_end[ki]:
                any_end[ki] = kt
    return total_cost

seq = list(range(n))
random.shuffle(seq)

# Benchmark
iters = 500
t0 = time.time()
for _ in range(iters):
    fast_eval_dict(seq)
t1 = time.time()
print(f'Dict-based: {(t1-t0)/iters*1000:.3f}ms per eval')

t0 = time.time()
for _ in range(iters):
    fast_eval_arr(seq)
t1 = time.time()
print(f'Array-based: {(t1-t0)/iters*1000:.3f}ms per eval')
